class ImVec2 {
    x;
    y;
    static ZERO = new ImVec2(0.0, 0.0);
    static UNIT = new ImVec2(1.0, 1.0);
    static UNIT_X = new ImVec2(1.0, 0.0);
    static UNIT_Y = new ImVec2(0.0, 1.0);
    constructor(x = 0.0, y = 0.0){
        this.x = x;
        this.y = y;
    }
    Set(x, y) {
        this.x = x;
        this.y = y;
        return this;
    }
    Copy(other) {
        this.x = other.x;
        this.y = other.y;
        return this;
    }
    Equals(other) {
        if (this.x !== other.x) {
            return false;
        }
        if (this.y !== other.y) {
            return false;
        }
        return true;
    }
}
