// IMGUI_API bool          BeginMenu(const char* label, bool enabled = true);                  // create a sub-menu entry. only call EndMenu() if this returns true!
// IMGUI_API void          EndMenu();                                                          // only call EndMenu() if BeginMenu() returns true!
// IMGUI_API bool          MenuItem(const char* label, const char* shortcut = NULL, bool selected = false, bool enabled = true);  // return true when activated. shortcuts are displayed for convenience but not processed by ImGui at the moment
// IMGUI_API bool          MenuItem(const char* label, const char* shortcut, bool* p_selected, bool enabled = true);              // return true when activated + toggle (*p_selected) if p_selected != NULL
function BeginMenuBar() {
    return bind.BeginMenuBar();
}
function EndMenuBar() {
    bind.EndMenuBar();
}
function BeginMainMenuBar() {
    return bind.BeginMainMenuBar();
}
function EndMainMenuBar() {
    bind.EndMainMenuBar();
}
function BeginMenu(label, enabled = true) {
    return bind.BeginMenu(label, enabled);
}
function EndMenu() {
    bind.EndMenu();
}
function MenuItem(label, ...args) {
    if (args.length === 0) {
        return bind.MenuItem_A(label, null, false, true);
    } else if (args.length === 1) {
        const shortcut = args[0];
        return bind.MenuItem_A(label, shortcut, false, true);
    } else {
        const shortcut = args[0];
        if (typeof args[1] === 'boolean') {
            const selected = args[1];
            const enabled = typeof args[2] === 'boolean' ? args[2] : true;
            return bind.MenuItem_A(label, shortcut, selected, enabled);
        } else {
            const p_selected = args[1];
            const enabled = typeof args[2] === 'boolean' ? args[2] : true;
            const ref_selected = Array.isArray(p_selected) ? p_selected : [
                p_selected()
            ];
            const ret = bind.MenuItem_B(label, shortcut, ref_selected, enabled);
            if (!Array.isArray(p_selected)) {
                p_selected(ref_selected[0]);
            }
            return ret;
        }
    }
}
