class Input {
    _dom_input;
    constructor(cvs){
        this._dom_input = document.createElement('input');
        // 该输入框仅用于 IME/文本输入中转，不应参与浏览器原生 Tab 焦点链。
        // 否则按 Tab 时会在真实控件与隐藏输入框之间来回切换，出现“无限自动切换”现象。
        this._dom_input.tabIndex = -1;
        this._dom_input.style.position = 'fixed';
        this._dom_input.style.top = -1e4 + 'px';
        this._dom_input.style.left = -1e4 + 'px';
        this._dom_input.addEventListener('keydown', (e)=>{
            e.stopPropagation();
            this.onKeydown(e);
            // 只拦截 Tab，避免触发浏览器原生焦点跳转；其余按键保留默认行为，
            // 否则会导致输入框内字符按键失效。
            if (e.key === 'Tab') {
                e.preventDefault();
            }
        });
        this._dom_input.addEventListener('keyup', (e)=>{
            e.stopPropagation();
            this.onKeyup(e);
            // 同上：仅拦截 Tab，避免影响文本输入。
            if (e.key === 'Tab') {
                e.preventDefault();
            }
        });
        this._dom_input.addEventListener('keypress', (e)=>{
            e.stopPropagation();
            this.onKeypress(e);
        });
        this._dom_input.addEventListener('compositionend', (e)=>{
            this.onCompositionEnd(e);
        });
        this._dom_input.addEventListener('paste', (e)=>{
            this.onPaste(e);
        });
        cvs.appendChild(this._dom_input);
        this.blur();
    }
    onKeydown(e) {
        canvas_on_keydown(e);
    }
    onKeyup(e) {
        canvas_on_keyup(e);
    }
    onKeypress(e) {
        e.preventDefault();
        canvas_on_keypress(e);
    }
    onCompositionEnd(e) {
        e.preventDefault();
        for(let i = 0; i < e.data.length; i++){
            const io = GetIO();
            io.AddInputCharacter(e.data.codePointAt(i));
        }
    }
    onPaste(e) {
        e.stopPropagation();
        const text = e.clipboardData?.getData('text/plain');
        if (typeof text === 'string') {
            clipboard_text = text;
        }
    }
    blur() {
        this._dom_input.blur();
    }
    focus() {
        this._dom_input.focus();
    }
}
