                    MAP_ANALOG(ImGuiNavInput.DpadUp, 5, -0.3, -0.9); // D-Pad Up
                    MAP_ANALOG(ImGuiNavInput.DpadDown, 5, 0.3, 0.9); // D-Pad Down
