                    MAP_BUTTON(ImGuiNavInput.FocusNext, 5); // R1 / RB
                    MAP_BUTTON(ImGuiNavInput.TweakSlow, 6); // L2 / LT
                    MAP_BUTTON(ImGuiNavInput.TweakFast, 7); // R2 / RT
                    MAP_ANALOG(ImGuiNavInput.LStickLeft, 0, -0.3, -0.9);
